&lt;p data-end=&quot;&quot; data-start=&quot;&quot;&gt;&lt;span align-items:=&quot;&quot; display:=&quot;&quot; gap:=&quot;&quot; style=&quot;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li .=&quot;&quot; august=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; finance=&quot;&quot; first=&quot;&quot; from=&quot;&quot; he=&quot;&quot; held=&quot;&quot; independent=&quot;&quot; k=&quot;&quot; li=&quot;&quot; march=&quot;&quot; minister=&quot;&quot; of=&quot;&quot; office=&quot;&quot; r=&quot;&quot; shanmugham=&quot;&quot; the=&quot;&quot; to=&quot;&quot; was=&quot;&quot;&gt;उन्होंने &lt;strong&gt;26 नवंबर, 1947&lt;/strong&gt; को &lt;strong&gt;स्वतंत्र भारत का पहला बजट&lt;/strong&gt; पेश किया। यह बजट भारत की आर्थिक नीतियों और वित्तीय योजना की नींव रखने के लिए उल्लेखनीय था।&lt;/li&gt;
	&lt;li .=&quot;&quot; 2=&quot;&quot; a=&quot;&quot; and=&quot;&quot; at=&quot;&quot; chetty=&quot;&quot; choice=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; expertise=&quot;&quot; finance=&quot;&quot; financial=&quot;&quot; font-weight:=&quot;&quot; for=&quot;&quot; him=&quot;&quot; his=&quot;&quot; in=&quot;&quot; is=&quot;&quot; li=&quot;&quot; made=&quot;&quot; matters=&quot;&quot; minister=&quot;&quot; natural=&quot;&quot; of=&quot;&quot; prominent=&quot;&quot; role=&quot;&quot; s=&quot;&quot; span=&quot;&quot; statement=&quot;&quot; style=&quot;&quot; the=&quot;&quot; time=&quot;&quot; was=&quot;&quot;&gt;उन्होंने स्वतंत्रता के बाद शुरुआती वर्षों के दौरान भारत के आर्थिक ढांचे की स्थापना में महत्वपूर्ण भूमिका निभाई, जिसमें &lt;strong&gt;खाद्य पदार्थों की कमी, शरणार्थियों के पुनर्वास और मुद्रास्फीति के प्रबंधन&lt;/strong&gt; जैसे मुद्दों को संबोधित करना शामिल था।&lt;/li&gt;
	&lt;li additional=&quot;&quot; align-items:=&quot;&quot; answer=&quot;&quot; cdn.testbook.com=&quot;&quot; certain=&quot;&quot; color:=&quot;&quot; correct=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; differences=&quot;&quot; display:=&quot;&quot; due=&quot;&quot; em=&quot;&quot; fiscal=&quot;&quot; font-size:=&quot;&quot; font-weight:=&quot;&quot; gap:=&quot;&quot; height=&quot;&quot; his=&quot;&quot; img=&quot;&quot; in=&quot;&quot; is=&quot;&quot; jawaharlal=&quot;&quot; k=&quot;&quot; li=&quot;&quot; lms_creative_elements=&quot;&quot; over=&quot;&quot; prime=&quot;&quot; r=&quot;&quot; resignation=&quot;&quot; resources=&quot;&quot; shanmugham=&quot;&quot; span=&quot;&quot; src=&quot;&quot; statement=&quot;&quot; style=&quot;&quot; the=&quot;&quot; then=&quot;&quot; to=&quot;&quot; vertical-align:=&quot;&quot; was=&quot;&quot; width=&quot;&quot; with=&quot;&quot;&gt;चेट्टी का जन्म &lt;strong&gt;1892&lt;/strong&gt; में &lt;strong&gt;कोयंबटूर, तमिलनाडु&lt;/strong&gt; में हुआ था। वह &lt;strong&gt;पेशे से वकील&lt;/strong&gt; थे और बाद में एक सफल उद्योगपति बने।&lt;/li&gt;
	&lt;li a=&quot;&quot; and=&quot;&quot; as=&quot;&quot; becoming=&quot;&quot; before=&quot;&quot; capacities=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; delegate=&quot;&quot; finance=&quot;&quot; he=&quot;&quot; held=&quot;&quot; in=&quot;&quot; including=&quot;&quot; legislative=&quot;&quot; li=&quot;&quot; madras=&quot;&quot; member=&quot;&quot; of=&quot;&quot; round=&quot;&quot; served=&quot;&quot; table=&quot;&quot; the=&quot;&quot; to=&quot;&quot; various=&quot;&quot;&gt;भारत की शुरुआती आर्थिक नीतियों को आकार देने में चेट्टी का योगदान महत्वपूर्ण था, खासकर ऐसे समय में जब देश को स्वतंत्रता के बाद भारी चुनौतियों का सामना करना पड़ा था।&lt;/li&gt;
&lt;/ul&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;अन्य विकल्प:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;जॉन मथाई:&lt;/strong&gt; उन्होंने आर के शनमुखम चेट्टी के बाद भारत के दूसरे वित्त मंत्री के रूप में पदभार संभाला। उन्होंने &lt;strong&gt;1949-50 का केंद्रीय बजट&lt;/strong&gt; पेश किया।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;रफी अहमद किदवई:&lt;/strong&gt; किदवई एक प्रमुख स्वतंत्रता सेनानी थे और स्वतंत्र भारत में &lt;strong&gt;संचार मंत्री&lt;/strong&gt; के रूप में कार्य किया। वह वित्त मंत्रालय से जुड़े नहीं थे।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;जयरामदास दौलतराम:&lt;/strong&gt; उन्होंने &lt;strong&gt;बिहार के राज्यपाल&lt;/strong&gt; के रूप में कार्य किया और बाद में असम के राज्यपाल बने। वह वित्त मंत्रालय से नहीं जुड़े थे।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत का पहला बजट:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li and=&quot;&quot; budget=&quot;&quot; by=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; economic=&quot;&quot; first=&quot;&quot; focused=&quot;&quot; independent=&quot;&quot; k=&quot;&quot; li=&quot;&quot; of=&quot;&quot; on=&quot;&quot; presented=&quot;&quot; r=&quot;&quot; recovery=&quot;&quot; shanmugham=&quot;&quot; the=&quot;&quot;&gt;इसने &lt;strong&gt;खाद्य पदार्थों की कमी&lt;/strong&gt;, &lt;strong&gt;शरणार्थियों के पुनर्वास&lt;/strong&gt; और &lt;strong&gt;रियासतों के वित्तीय एकीकरण&lt;/strong&gt; जैसे महत्वपूर्ण मुद्दों को संबोधित किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;आर के शनमुखम चेट्टी के प्रमुख योगदान:&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li and=&quot;&quot; balanced=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; economic=&quot;&quot; emphasized=&quot;&quot; financial=&quot;&quot; for=&quot;&quot; foundation=&quot;&quot; he=&quot;&quot; importance=&quot;&quot; laid=&quot;&quot; li=&quot;&quot; of=&quot;&quot; s=&quot;&quot; the=&quot;&quot;&gt;उन्होंने &lt;strong&gt;विभाजन&lt;/strong&gt; से उत्पन्न चुनौतियों का समाधान किया, जैसे कि विस्थापित व्यक्तियों के पुनर्वास और राजकोषीय घाटे का प्रबंधन करने की आवश्यकता।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विरासत:&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li as=&quot;&quot; contributions=&quot;&quot; crucial=&quot;&quot; data-end=&quot;&quot; data-start=&quot;&quot; economic=&quot;&quot; establishing=&quot;&quot; finance=&quot;&quot; his=&quot;&quot; in=&quot;&quot; li=&quot;&quot; minister=&quot;&quot; s=&quot;&quot; tenure=&quot;&quot; though=&quot;&quot; was=&quot;&quot; were=&quot;&quot;&gt;उनकी नीतियों ने भारत में बाद की वित्तीय योजना के लिए एक रोडमैप प्रदान किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct answer is &lt;u&gt;&lt;strong&gt;Achieving significant growth in services and manufacturing sectors&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;The &lt;strong&gt;1991 economic reforms&lt;/strong&gt;, also known as the &lt;strong&gt;Liberalization, Privatization, and Globalization (LPG) reforms&lt;/strong&gt;, marked a major shift in India&amp;rsquo;s economic policy under the leadership of &lt;strong&gt;Dr. Manmohan Singh&lt;/strong&gt;, the then Finance Minister.&lt;/li&gt;
	&lt;li&gt;These reforms aimed at transforming India into a more &lt;strong&gt;market-driven economy&lt;/strong&gt; by reducing state control and encouraging private sector participation.&lt;/li&gt;
	&lt;li&gt;The reforms placed a strong emphasis on developing the &lt;strong&gt;services and manufacturing sectors&lt;/strong&gt;, which were identified as key drivers of economic growth.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;services sector&lt;/strong&gt;, including areas like &lt;strong&gt;information technology (IT), financial services, telecommunications, and tourism&lt;/strong&gt;, became the backbone of India&amp;rsquo;s economy, contributing significantly to its &lt;strong&gt;GDP growth&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;manufacturing sector&lt;/strong&gt; also saw increased investment and policy support to boost &lt;strong&gt;industrial productivity&lt;/strong&gt; and generate employment.&lt;/li&gt;
	&lt;li&gt;The reforms facilitated foreign investment and technology inflow, which helped India establish a competitive edge in the &lt;strong&gt;global market&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The focus on these sectors led to a higher pace of &lt;strong&gt;economic growth&lt;/strong&gt;, improved infrastructure, and a significant rise in &lt;strong&gt;export revenues&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;The strategy was aligned with global economic trends, capitalizing on India&amp;#39;s &lt;strong&gt;skilled workforce&lt;/strong&gt; and expanding urban markets.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Reducing dependency on the information technology sector&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;India did not aim to reduce dependency on the &lt;strong&gt;information technology (IT) sector&lt;/strong&gt;; rather, IT became a cornerstone of India&amp;rsquo;s economic growth post-1991 reforms.&lt;/li&gt;
		&lt;li&gt;The IT sector has been a significant contributor to India&amp;rsquo;s &lt;strong&gt;exports&lt;/strong&gt; and GDP, transforming cities like &lt;strong&gt;Bengaluru&lt;/strong&gt; into global IT hubs.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Maintaining an agrarian economy with limited industrial growth&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;India&amp;rsquo;s economic reforms were focused on moving away from a primarily &lt;strong&gt;agrarian economy&lt;/strong&gt; to a more diversified economy with robust industrial and services sectors.&lt;/li&gt;
		&lt;li&gt;While agriculture remains important, the reforms aimed at reducing over-dependence on agriculture for economic stability.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Eliminating foreign trade to boost domestic production&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Instead of eliminating foreign trade, the 1991 reforms encouraged greater &lt;strong&gt;international trade&lt;/strong&gt; and integration with the global economy.&lt;/li&gt;
		&lt;li&gt;Policies like the reduction of tariffs and liberalization of trade boosted &lt;strong&gt;export-oriented growth&lt;/strong&gt; and attracted &lt;strong&gt;foreign direct investment (FDI)&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;सेवाओं और विनिर्माण क्षेत्रों में महत्वपूर्ण वृद्धि हासिल करना&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: (33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;strong&gt;1991 के आर्थिक सुधार&lt;/strong&gt; , जिन्हें &lt;strong&gt;उदारीकरण, निजीकरण और वैश्वीकरण (LPG) सुधार&lt;/strong&gt; के रूप में भी जाना जाता है, तत्कालीन वित्त मंत्री &lt;strong&gt;डॉ. मनमोहन सिंह&lt;/strong&gt; के नेतृत्व में भारत की आर्थिक नीति में एक बड़ा बदलाव था।&lt;/li&gt;
	&lt;li&gt;इन सुधारों का उद्देश्य राज्य नियंत्रण को कम करके और निजी क्षेत्र की भागीदारी को प्रोत्साहित करके भारत को अधिक &lt;strong&gt;बाजार-संचालित अर्थव्यवस्था&lt;/strong&gt; में बदलना था।&lt;/li&gt;
	&lt;li&gt;सुधारों में &lt;strong&gt;सेवा और विनिर्माण क्षेत्र के&lt;/strong&gt; विकास पर जोर दिया गया, जिन्हें आर्थिक विकास के प्रमुख चालक के रूप में पहचाना गया।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;सूचना प्रौद्योगिकी (IT), वित्तीय सेवाएं, दूरसंचार और पर्यटन&lt;/strong&gt; जैसे क्षेत्रों सहित &lt;strong&gt;सेवा क्षेत्र&lt;/strong&gt; भारत की अर्थव्यवस्था की रीढ़ बन गया है, जिसने इसके &lt;strong&gt;सकल घरेलू उत्पाद की वृद्धि&lt;/strong&gt; में महत्वपूर्ण योगदान दिया है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;विनिर्माण क्षेत्र में&lt;/strong&gt; भी &lt;strong&gt;औद्योगिक उत्पादकता&lt;/strong&gt; बढ़ाने और रोजगार सृजन के लिए निवेश और नीतिगत समर्थन में वृद्धि देखी गई।&lt;/li&gt;
	&lt;li&gt;इन सुधारों से विदेशी निवेश और प्रौद्योगिकी प्रवाह सुगम हुआ, जिससे भारत को &lt;strong&gt;वैश्विक बाजार&lt;/strong&gt; में प्रतिस्पर्धात्मक बढ़त प्राप्त करने में सहायता मिली।&lt;/li&gt;
	&lt;li&gt;इन क्षेत्रों पर ध्यान केंद्रित करने से &lt;strong&gt;आर्थिक विकास&lt;/strong&gt; की गति तेज हुई, बुनियादी ढांचे में सुधार हुआ और &lt;strong&gt;निर्यात राजस्व&lt;/strong&gt; में उल्लेखनीय वृद्धि हुई।&lt;/li&gt;
	&lt;li&gt;यह रणनीति वैश्विक आर्थिक रुझानों के अनुरूप थी, जिसमें भारत के &lt;strong&gt;कुशल कार्यबल का&lt;/strong&gt; लाभ उठाना और शहरी बाजारों का विस्तार करना शामिल था।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;सूचना प्रौद्योगिकी क्षेत्र पर निर्भरता कम करना&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;भारत का उद्देश्य &lt;strong&gt;सूचना प्रौद्योगिकी (IT) क्षेत्र&lt;/strong&gt; पर निर्भरता कम करना नहीं था, बल्कि, IT 1991 के सुधारों के बाद भारत की आर्थिक वृद्धि की आधारशिला बन गयी।&lt;/li&gt;
		&lt;li&gt;IT क्षेत्र भारत के &lt;strong&gt;निर्यात&lt;/strong&gt; और सकल घरेलू उत्पाद में महत्वपूर्ण योगदानकर्ता रहा है, जिसने &lt;strong&gt;बेंगलुरु&lt;/strong&gt; जैसे शहरों को वैश्विक IT केन्द्रों में परिवर्तित कर दिया है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;सीमित औद्योगिक विकास के साथ कृषि अर्थव्यवस्था को बनाए रखना&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;भारत के आर्थिक सुधार मुख्यतः &lt;strong&gt;कृषि प्रधान अर्थव्यवस्था&lt;/strong&gt; से हटकर मजबूत औद्योगिक और सेवा क्षेत्रों वाली अधिक विविध अर्थव्यवस्था की ओर बढ़ने पर केंद्रित थे।&lt;/li&gt;
		&lt;li&gt;यद्यपि कृषि अभी भी महत्वपूर्ण है, तथापि सुधारों का उद्देश्य आर्थिक स्थिरता के लिए कृषि पर अत्यधिक निर्भरता को कम करना है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;घरेलू उत्पादन को बढ़ावा देने के लिए विदेशी व्यापार को समाप्त करना&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;विदेशी व्यापार को समाप्त करने के बजाय, 1991 के सुधारों ने अधिकाधिक &lt;strong&gt;अंतर्राष्ट्रीय व्यापार&lt;/strong&gt; और वैश्विक अर्थव्यवस्था के साथ एकीकरण को प्रोत्साहित किया।&lt;/li&gt;
		&lt;li&gt;टैरिफ में कमी और व्यापार के उदारीकरण जैसी नीतियों ने &lt;strong&gt;निर्यातोन्मुखी विकास को&lt;/strong&gt; बढ़ावा दिया और &lt;strong&gt;प्रत्यक्ष विदेशी निवेश (FDI) को&lt;/strong&gt; आकर्षित किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;150&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;The National Food for Work Programme (NFWP)&lt;/span&gt;&amp;nbsp;was launched in India in&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;2004.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;It was a component of the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Rural Employment Guarantee Scheme (NREGS)&lt;/span&gt;&amp;nbsp;later renamed as the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahatma Gandhi National Rural Employment Guarantee Scheme (MGNREGS).&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;The NFWP aimed to provide&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;food security&lt;/span&gt;&amp;nbsp;to rural populations by offering&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;employment opportunities in labour-intensive projects.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;Workers participating in the NFWP&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;received food grains as remuneration&amp;nbsp;&lt;/span&gt;for their work.&lt;/li&gt;
	&lt;li&gt;The NFWP was integrated into the broader framework of the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;MGNREGS, expanding the scope and coverage of the employment guarantee program.&lt;span style=&quot;font-weight: bolder;&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Mahatma Gandhi National Rural Employment Guarantee Scheme (MGNREGS).&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;The Mahatma Gandhi National Rural Employment Guarantee Scheme (MGNREGS)&lt;/span&gt;&amp;nbsp;is a&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;social security and employment guarantee program&lt;/span&gt;&amp;nbsp;in India.&lt;/li&gt;
		&lt;li&gt;It was enacted&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;in 2005&lt;/span&gt;&amp;nbsp;under the&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Rural Employment Guarantee Act (NREGA).&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;The program provides a&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;legal guarantee for 100 days of wage employment&lt;/span&gt;&amp;nbsp;in a financial year&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;to rural households.&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;MGNREGS focuses on&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;labour-intensive projects&amp;nbsp;&lt;/span&gt;such as&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;nbsp;road construction, water conservation, and irrigation&amp;nbsp;&lt;/span&gt;to create employment opportunities and improve rural infrastructure.&lt;/li&gt;
		&lt;li&gt;The scheme ensures timely payment of wages, provides social security provisions, and promotes transparency through mandatory public disclosure of information.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br><p>সঠিক উত্তর হল <u><strong>150</strong></u></p>

<p><span style="display: flex;gap: 6px;align-items: center;"><span style="display: flex;gap: 6px;align-items: center;"><img height="26px" src="//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png" width="26px" /><strong><span style="vertical-align: middle;font-size: 21px;"><u>Key Points</u></span></strong></span>&nbsp;</span></p>

<ul style="color: rgb(33, 37, 41);">
	<li><span style="font-weight: bolder;">জাতীয় খাদ্যের বিনিময়ে কাজ কর্মসূচি (NFWP)</span> ভারতে <span style="font-weight: bolder;">2004 সালে</span> চালু করা হয়েছিল।</li>
	<li>এটি <span style="font-weight: bolder;">জাতীয় গ্রামীণ কর্মসংস্থান গ্যারান্টি স্কিম (NREGS)</span> এর একটি অংশ ছিল, যা পরে <span style="font-weight: bolder;">মহাত্মা গান্ধী জাতীয় গ্রামীণ কর্মসংস্থান গ্যারান্টি স্কিম (MGNREGS)</span> নামে পরিচিত।</li>
	<li>NFWP এর লক্ষ্য ছিল <span style="font-weight: bolder;">গ্রামীণ জনগোষ্ঠীর খাদ্য নিরাপত্তা</span> নিশ্চিত করা, <span style="font-weight: bolder;">শ্রম-নির্ভর প্রকল্পগুলিতে কর্মসংস্থানের সুযোগ</span> প্রদান করে।</li>
	<li>NFWP-তে অংশগ্রহণকারী কর্মীরা তাদের কাজের জন্য <span style="font-weight: bolder;">খাদ্যশস্য প্রাপ্ত</span> করেছিলেন।</li>
	<li>NFWP <span style="font-weight: bolder;">MGNREGS এর বৃহত্তর কাঠামোর সাথে একীভূত</span> হয়েছিল, কর্মসংস্থান গ্যারান্টি কর্মসূচির পরিধি এবং আওতা বিস্তৃত করে।<span style="font-weight: bolder;">​</span></li>
</ul>

<p><span style="display: flex;gap: 6px;align-items: center;"><img height="26px" src="//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png" width="26px" /><strong><span style="vertical-align: middle;font-size: 21px;"><u>Additional Information</u></span></strong></span></p>

<ul style="color: rgb(33, 37, 41);">
	<li><span style="font-weight: bolder;">মহাত্মা গান্ধী জাতীয় গ্রামীণ কর্মসংস্থান গ্যারান্টি স্কিম (MGNREGS).</span>

	<ul>
		<li><span style="font-weight: bolder;">মহাত্মা গান্ধী জাতীয় গ্রামীণ কর্মসংস্থান গ্যারান্টি স্কিম (MGNREGS)</span> ভারতের একটি <span style="font-weight: bolder;">সামাজিক নিরাপত্তা এবং কর্মসংস্থান গ্যারান্টি কর্মসূচি</span>।</li>
		<li>এটি <span style="font-weight: bolder;">2005 সালে</span> <span style="font-weight: bolder;">জাতীয় গ্রামীণ কর্মসংস্থান গ্যারান্টি আইন (NREGA)</span> এর অধীনে প্রণয়ন করা হয়েছিল।</li>
		<li>এই কর্মসূচি <span style="font-weight: bolder;">গ্রামীণ পরিবারগুলিকে</span> একটি আর্থিক বছরে <span style="font-weight: bolder;">100 দিনের মজুরিযুক্ত কর্মসংস্থানের আইনি গ্যারান্টি</span> প্রদান করে।</li>
		<li>MGNREGS <span style="font-weight: bolder;">শ্রম-নির্ভর প্রকল্পগুলিতে</span> মনোযোগ দেয়, যেমন <span style="font-weight: bolder;">সড়ক নির্মাণ, জল সংরক্ষণ এবং সেচ</span>, কর্মসংস্থানের সুযোগ তৈরি করতে এবং গ্রামীণ অবকাঠামো উন্নত করতে।</li>
		<li>এই স্কিম সময়মতো মজুরি প্রদান নিশ্চিত করে, সামাজিক নিরাপত্তার ব্যবস্থা প্রদান করে এবং তথ্যের বাধ্যতামূলক জনসাধারণের প্রকাশের মাধ্যমে স্বচ্ছতা প্রচার করে।</li>
	</ul>
	</li>
</ul>
